// ===== UBIKAIS NOTAM 크롤링 (기존 로직 유지) =====
const BASE_URL = 'https://ubikais.fois.go.kr:8030';
const helpers = this.helpers;

const loginResponse = $input.first().json;
let cookies = '';
if (loginResponse.headers && loginResponse.headers['set-cookie']) {
  const setCookies = loginResponse.headers['set-cookie'];
  cookies = (Array.isArray(setCookies) ? setCookies : [setCookies])
    .map(c => c.split(';')[0]).join('; ');
}

const now = new Date();
const y = now.getFullYear();
const m = String(now.getMonth() + 1).padStart(2, '0');
const d = String(now.getDate()).padStart(2, '0');
const today = `${y}-${m}-${d}`;
const yy = String(y).slice(2);
const todayShort = `${yy}${m}${d}`;

async function crawl(endpoint, params) {
  const qs = Object.entries(params).map(([k, v]) => encodeURIComponent(k) + '=' + encodeURIComponent(String(v))).join('&');
  try {
    return await helpers.httpRequest({
      url: BASE_URL + endpoint + '?' + qs,
      method: 'GET',
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
        'Accept': 'application/json, text/javascript, */*; q=0.01',
        'X-Requested-With': 'XMLHttpRequest',
        'Referer': BASE_URL + '/sysUbikais/biz/main.ubikais',
        'Cookie': cookies
      },
      skipSslCertificateValidation: true,
      json: true
    });
  } catch (e) { return { error: e.message }; }
}
function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

const allRecords = [];
const counts = { fir: {}, ad: {}, snowtam: 0, prohibited: 0 };

// === FIR NOTAM ===
for (const series of ['C', 'A', 'D']) {
  const result = await crawl('/sysUbikais/biz/nps/selectNotamRecFir.fois', {
    downloadYn: '1', srchFir: 'RKRR', srchAd: 'RKRR', srchSeries: series,
    srchValid: today, srchValidsh: todayShort + '2359',
    srchValidsh2: todayShort + '0000', srchValid2: '1',
    cmd: 'get-records', limit: '1000', offset: '0'
  });
  const recs = result?.records || [];
  counts.fir[series] = recs.length;
  for (const r of recs) {
    allRecords.push({ ...r, _sourceType: 'domestic', _sourceGroup: series });
  }
  await sleep(500);
}

// === AD NOTAM ===
const airports = ['RKSI', 'RKSS', 'RKPC', 'RKPK', 'RKPU', 'RKJJ', 'RKTN'];
for (const airport of airports) {
  const result = await crawl('/sysUbikais/biz/nps/selectNotamRecAd.fois', {
    downloadYn: '1', srchFir: 'RKRR', srchSeries: 'C', srchAd: airport,
    srchValid: today, srchValidsh: todayShort + '2359',
    srchValidsh2: todayShort + '0000', srchValid2: '1',
    cmd: 'get-records', limit: '1000', offset: '0'
  });
  const recs = result?.records || [];
  counts.ad[airport] = recs.length;
  for (const r of recs) {
    allRecords.push({ ...r, _sourceType: 'international', _sourceGroup: airport });
  }
  await sleep(300);
}

// === SNOWTAM ===
const snowResult = await crawl('/sysUbikais/biz/nps/selectNotamRecSnow.fois', {
  downloadYn: '1', printYn: '', srchOriginator: '', srchSeq: '',
  srchAd: '', srchValidFrom: String(y),
  cmd: 'get-records', limit: '1000', offset: '0'
});
const snowRecs = snowResult?.records || [];
counts.snowtam = snowRecs.length;
for (const r of snowRecs) {
  allRecords.push({ ...r, _sourceType: 'snowtam', _sourceGroup: 'SNOW' });
}

// === 금지구역 ===
const prohibResult = await crawl('/sysUbikais/biz/nps/selectRecOffZone.fois', {
  downloadYn: '1', srchFir: 'RKRR', srchSeries: 'D', srchQcode: 'QRP',
  srchValid: today, srchValidsh: todayShort + '2359',
  srchValidsh2: todayShort + '0000', srchValid2: '1',
  cmd: 'get-records', limit: '1000', offset: '0'
});
const prohibRecs = prohibResult?.records || [];
counts.prohibited = prohibRecs.length;
for (const r of prohibRecs) {
  allRecords.push({ ...r, _sourceType: 'domestic', _sourceGroup: 'D' });
}

return [{
  json: {
    allRecords,
    counts,
    crawledAt: now.toISOString(),
    totalRaw: allRecords.length
  }
}];

// ===== UBIKAIS 레코드 → Supabase notams 테이블 포맷 변환 + Upsert =====
const SUPABASE_URL = 'https://mysfgjaggqknuhobwtrc.supabase.co';
const SERVICE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im15c2ZnamFnZ3FrbnVob2J3dHJjIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc2OTg5NjAxNSwiZXhwIjoyMDg1NDcyMDE1fQ.ke-cuuQlx6kphA7gyA3crren2ARVZHWdji-5OlKiKCM';
const helpers = this.helpers;
const startMs = Date.now();

const { allRecords, counts, crawledAt, totalRaw } = $input.first().json;

// Q-line 좌표 파싱 (DDMMN/DDDMME format from ntCoord or amsOriginal)
function parseQLine(fullText) {
  if (!fullText) return {};
  const m = fullText.match(/Q\)\s*(\w+)\/(\w+)\/\w+\/\w+\/\w+\/(\d{3})\/(\d{3})\/(\d{4})([NS])(\d{5})([EW])(\d{3})/);
  if (!m) return {};
  const latDeg = parseInt(m[4].substring(0, 2), 10);
  const latMin = parseInt(m[4].substring(2, 4), 10);
  let lat = latDeg + latMin / 60;
  if (m[5] === 'S') lat = -lat;
  const lonDeg = parseInt(m[6].substring(0, 3), 10);
  const lonMin = parseInt(m[6].substring(3, 5), 10);
  let lon = lonDeg + lonMin / 60;
  if (m[7] === 'W') lon = -lon;
  return {
    fir: m[1], qcode: m[2],
    q_lower_alt: parseInt(m[3], 10) * 100,
    q_upper_alt: parseInt(m[4] ? m[3] : '0', 10) * 100,
    q_lat: lat, q_lon: lon,
    q_radius_nm: parseInt(m[8], 10)
  };
}

// UBIKAIS 레코드 → DB 레코드 변환
function transformRecord(rec) {
  const series = rec.ntSeries || '';
  const seq = rec.ntSndSeq || '';
  const year = rec.ntYear || '';
  const notamNumber = (series && seq && year) ? `${series}${seq}/${year}` : `UNK_${rec.ntmPk || rec.id}`;

  const fullText = rec.amsOriginal || '';
  const parsed = parseQLine(fullText);

  let effectiveEnd = rec.ntEndDate || '';
  if (rec.ntPerm === 'PERM') effectiveEnd = 'PERM';
  else if (rec.ntPerm === 'EST' && effectiveEnd) effectiveEnd = effectiveEnd + 'EST';

  return {
    notam_number: notamNumber,
    location: rec.ntAd || '',
    full_text: fullText,
    e_text: rec.ntText || '',
    qcode: rec.ntCode || parsed.qcode || '',
    qcode_mean: rec.ntCodeDesc || '',
    effective_start: rec.ntStartDate || '',
    effective_end: effectiveEnd,
    series: series,
    fir: rec.ntFir || parsed.fir || '',
    issue_time: rec.ntSendDate || '',
    ais_type: rec.ntStatus || '',
    seq: seq,
    q_lat: parsed.q_lat || null,
    q_lon: parsed.q_lon || null,
    q_radius_nm: parsed.q_radius_nm || null,
    q_lower_alt: parsed.q_lower_alt || (rec.ntLower ? parseInt(rec.ntLower, 10) * 100 : null),
    q_upper_alt: parsed.q_upper_alt || (rec.ntUpper ? parseInt(rec.ntUpper, 10) * 100 : null),
    source_type: rec._sourceType || 'domestic',
    source_group: rec._sourceGroup || series,
    crawled_at: crawledAt
  };
}

// 변환
const dbRecords = allRecords
  .filter(r => r.ntmPk || r.id)
  .map(transformRecord)
  .filter(r => r.notam_number && !r.notam_number.startsWith('UNK_'));

// 50개씩 배치 upsert (PostgREST 제한 고려)
const BATCH_SIZE = 50;
let upsertedTotal = 0;
let errors = [];

for (let i = 0; i < dbRecords.length; i += BATCH_SIZE) {
  const batch = dbRecords.slice(i, i + BATCH_SIZE);
  try {
    const response = await helpers.httpRequest({
      url: `${SUPABASE_URL}/rest/v1/notams`,
      method: 'POST',
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'resolution=merge-duplicates,return=minimal'
      },
      body: JSON.stringify(batch),
      json: false
    });
    upsertedTotal += batch.length;
  } catch (e) {
    errors.push(`Batch ${i}: ${e.message}`);
  }
}

// 크롤 로그 기록
const executionMs = Date.now() - startMs;
const logEntry = {
  crawled_at: crawledAt,
  source: 'ubikais',
  domestic_a: counts.fir?.A || 0,
  domestic_c: counts.fir?.C || 0,
  domestic_d: counts.fir?.D || 0,
  domestic_e: 0,
  international: Object.values(counts.ad || {}).reduce((s, v) => s + v, 0),
  snowtam: counts.snowtam || 0,
  total_upserted: upsertedTotal,
  total_records: totalRaw,
  status: errors.length === 0 ? 'success' : 'partial',
  error_message: errors.length > 0 ? errors.join('; ') : null,
  execution_ms: executionMs
};

try {
  await helpers.httpRequest({
    url: `${SUPABASE_URL}/rest/v1/notam_crawl_logs`,
    method: 'POST',
    headers: {
      'apikey': SERVICE_KEY,
      'Authorization': `Bearer ${SERVICE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: JSON.stringify(logEntry),
    json: false
  });
} catch (e) { /* log failure is non-fatal */ }

return [{
  json: {
    upsertedTotal,
    totalRaw,
    dbRecordsCount: dbRecords.length,
    errors,
    executionMs,
    counts,
    crawledAt,
    status: errors.length === 0 ? 'SUCCESS' : 'PARTIAL'
  }
}];
